#!/bin/bash
set -e
cd "$(dirname "$0")"

mkdir -p app/guide/zangyodai-miharai-soudan
python3 -c "import base64; open('app/guide/zangyodai-miharai-soudan/page.tsx', 'wb').write(base64.b64decode(''))"
